#!/usr/bin/env python
import sys

class Solution:
    def dfs(self, node, graph, visited, currentPath):
        if visited[node]: return False
        visited[node] = True
        currentPath[node] = True
        for neighbor in graph[node]:
            if self.dfs(neighbor, graph, visited, currentPath): return True
        currentPath[node] = False
        return False
    def solve(self, graph):
        visited = [False] * len(graph)
        currentPath = [False] * len(graph)
        for i in range(len(graph)):
            if not visited[i] and self.dfs(i, graph, visited, currentPath):
                return True
        return False

    def main(self):
        n = int(sys.stdin.readline())
        graph = [[] for _ in range(n)]
        for _ in range(n-1):
            u, v = [int(x) for x in sys.stdin.readline().split()]
            graph[u].append(v)
            graph[v].append(u)

        print(self.solve(graph))

if __name__ == '__main__':
    solution = Solution()
    solution.main()

